+        let result = resolver.resolve(&v1, &v2).unwrap();
+        assert_eq!(result.value, 300);
+    }
+
+    #[test]
+    fn test_max_merge() {
+        let v1 = Versioned::new(100, "r1".to_string());
+        let v2 = Versioned::new(200, "r2".to_string());
+
+        let resolver = MaxMerge;
+        let result = resolver.resolve(&v1, &v2).unwrap();
+        assert_eq!(result.value, 200);
