+        let mut set = ReplicaSet::new("cluster-1");
+        set.add_replica("r1", "127.0.0.1:9001", ReplicaRole::Primary)
+            .unwrap();
+        set.add_replica("r2", "127.0.0.1:9002", ReplicaRole::Secondary)
+            .unwrap();
