+        let arr = Array::new();
+        for (alias, collection) in aliases {
+            let pair = Array::new();
+            pair.push(&JsValue::from_str(&alias));
+            pair.push(&JsValue::from_str(&collection));
+            arr.push(&pair);
+        }
+
+        arr.into()
+    }
+}
